import {useState, useEffect } from 'react';
import React from 'react';
import Modalcontrol from "./modal";
import {  Link} from "react-router-dom";

const Userlist = () =>{
    let [userlist, picklist] = useState([]);

    const getusers = () =>{
        let url = "http://localhost:3333/user";
        fetch(url)
        .then(responsedata => responsedata.json())
        .then(data => {
            picklist(data);
        })
     }

     const deleteuser = (id) =>{
        let url = "http://localhost:3333/user/"+id;
      let postoption = {method: "DELETE"};
      fetch(url, postoption)
      .then(response => response.json())
      .then(Array =>{
         alert(Array.message);
         window.location.reload();
           })
     }

     const showdetails = (id) =>{
           <Modalcontrol userid = {id}/>
        }
     

    useEffect(()=>{
        getusers();
    },[1])

    return(
        <div className="container mt-4">
        <div className="row">
     {
           
          userlist.map((user, index) => {
           
            return (
                <div class="col-lg-3 mb-4 " key={index} >
                   <div class="card" onClick={showdetails(this, user._id)}>
                    <div class="card-header bg-primary text-white text-right">
                    <i class="fa-solid fa-trash-can p-3" onClick={deleteuser.bind(this, user._id)}></i>
                    <Link to={`/edituser/${user._id}`}> <button >Edit</button>  </Link> 
                    </div>
                    <div class="card-body">
                      <div className=" mb-4 " key={index}>
                        <div className="p-3 text-center ">
                            <p className="mb-3"> {user.name} </p>
                            <p className="mb-3"> {user.email} </p>
                            <p className="mb-3">Rs. {user.mobile} </p>
                       </div>
                      </div>
                    </div>
                    <div class="card-footer bg-dark text-white text-center"> 
                      
                    </div>
                   </div>
                </div>
             
            );
          
       })
      }
        </div>
      </div>
    
    )
}

export default Userlist;
